using Financeiro.Application.Common; using Financeiro.Application.DTOs; using Financeiro.Application.Interfaces; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc;
namespace Financeiro.API.Controllers; [ApiController][Route("api/auth")] public class AuthController : ControllerBase { private readonly IAuthService _auth; public AuthController(IAuthService auth){_auth=auth;} [AllowAnonymous][HttpPost("login")] public async Task<IActionResult> Login([FromBody] LoginRequestDto request, CancellationToken cancellationToken){ var result = await _auth.LoginAsync(request,cancellationToken); if(!result.Success) return Unauthorized(result); return Ok(result); } }
